"use client";

import { useState } from "react";
import { useQuery, useMutation, gql } from "@apollo/client";
import {
    XAxis, YAxis, CartesianGrid,
    Tooltip, ResponsiveContainer, AreaChart, Area
} from "recharts";
import {
    Clock, Wallet,
    Plus, Minus, ArrowUp, ArrowDown,
    Activity
} from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { useRealTimePrice } from "@/lib/hooks/useRealTimePrice";
import { toast } from "sonner";

const DASHBOARD_QUERY = gql`
  query GetDashboardData($symbol: String!, $days: Int!) {
    me {
      id
      username
    }
    portfolios {
      id
      name
      balance
    }
    priceHistory(symbol: $symbol, days: $days) {
      price
      date
    }
  }
`;

const ADD_CASH_MUTATION = gql`
  mutation AddCash($portfolioId: ID!, $amount: Float!) {
    addCash(portfolioId: $portfolioId, amount: $amount) {
      id
      balance
    }
  }
`;

const BUY_ASSET_MUTATION = gql`
  mutation BuyAsset($portfolioId: ID!, $symbol: String!, $quantity: Float!, $price: Float!) {
    buyAsset(portfolioId: $portfolioId, symbol: $symbol, quantity: $quantity, price: $price) {
      id
      balance
      positions {
        symbol
        quantity
      }
    }
  }
`;

const CREATE_PORTFOLIO_MUTATION = gql`
  mutation CreatePortfolio($name: String!, $description: String) {
    createPortfolio(name: $name, description: $description) {
      id
      name
    }
  }
`;

const WATCHLIST = ["BTC-USD", "ETH-USD", "AAPL", "TSLA", "NVDA", "MSFT"];

export default function DashboardPage() {
    const [activeSymbol, setActiveSymbol] = useState("BTC-USD");
    const realTimePrice = useRealTimePrice(activeSymbol);

    const { data, loading, error, refetch } = useQuery(DASHBOARD_QUERY, {
        variables: { symbol: activeSymbol, days: 30 },
        pollInterval: 60000,
    });

    const [createPortfolio] = useMutation(CREATE_PORTFOLIO_MUTATION, {
        onCompleted: () => {
            toast.success("¡Portafolio 'Inversiones' creado!");
            refetch();
        },
        onError: (err) => toast.error(`Error: ${err.message}`)
    });

    const [addCash] = useMutation(ADD_CASH_MUTATION, {
        onCompleted: () => {
            toast.success("¡Depósito completado!");
            refetch();
        },
        onError: (err) => toast.error(`Error: ${err.message}`)
    });

    const [buyAsset] = useMutation(BUY_ASSET_MUTATION, {
        onCompleted: () => {
            toast.success("¡Compra ejecutada!");
            refetch();
        },
        onError: (err) => toast.error(`Error: ${err.message}`)
    });

    const currentPrice = realTimePrice || (data?.priceHistory?.length > 0
        ? data.priceHistory[data.priceHistory.length - 1].price
        : 0);

    const handleAction = async (type: string) => {
        const portfolio = data?.portfolios?.[0];
        if (!portfolio) {
            toast.error("No tienes portafolios. Crea uno en la terminal primero.");
            return;
        }

        if (type === 'DEPÓSITO') {
            await addCash({ variables: { portfolioId: portfolio.id, amount: 1000.0 } });
        } else if (type === 'COMPRA') {
            await buyAsset({
                variables: {
                    portfolioId: portfolio.id,
                    symbol: activeSymbol,
                    quantity: 0.1,
                    price: Number(currentPrice)
                }
            });
        }
    };

    if (error) return <div className="p-10 text-red-400 font-mono">ERROR_DASHBOARD: {error.message}</div>;

    return (
        <div className="space-y-8 animate-in fade-in duration-1000">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                    <h1 className="text-4xl font-bold tracking-tighter">TERMINAL_CENTRAL</h1>
                    <div className="flex items-center gap-2 mt-2">
                        <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                        <p className="text-slate-500 uppercase text-[10px] tracking-[0.3em]">System_Online // Feed: Live</p>
                    </div>
                </div>

                {data?.portfolios?.length === 0 && (
                    <Button
                        onClick={() => createPortfolio({ variables: { name: "Inversiones", description: "Mi primer portafolio" } })}
                        className="bg-blue-600 hover:bg-blue-700 text-white font-bold"
                    >
                        <Plus size={16} className="mr-2" /> CREAR MI PRIMER PORTAFOLIO
                    </Button>
                )}

                <div className="flex items-center gap-4 bg-white/5 p-4 rounded-2xl border border-white/5">
                    <div className="text-right">
                        <p className="text-slate-500 text-[10px] uppercase tracking-widest font-bold">Active_Ticker</p>
                        <p className="text-2xl font-black italic">{activeSymbol}</p>
                    </div>
                    <div className="h-10 w-px bg-white/10 mx-2" />
                    <div className="text-left">
                        <p className="text-slate-500 text-[10px] uppercase tracking-widest">Last_Price</p>
                        <p className="text-2xl font-mono text-white">${Number(currentPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
                <div className="xl:col-span-3 space-y-8">
                    <Card className="glass border-none overflow-hidden">
                        <CardHeader className="flex flex-row items-center justify-between pb-2">
                            <CardTitle className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                Price_History_30D
                            </CardTitle>
                            <Clock size={14} className="text-slate-500" />
                        </CardHeader>
                        <CardContent className="h-[400px] w-full pt-4">
                            {loading ? (
                                <div className="h-full w-full flex items-center justify-center">
                                    <Activity className="animate-spin text-white/20" size={40} />
                                </div>
                            ) : (
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={data?.priceHistory}>
                                        <defs>
                                            <linearGradient id="colorPrice" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="5%" stopColor="#fff" stopOpacity={0.1} />
                                                <stop offset="95%" stopColor="#fff" stopOpacity={0} />
                                            </linearGradient>
                                        </defs>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                                        <XAxis
                                            dataKey="date"
                                            axisLine={false}
                                            tickLine={false}
                                            tick={{ fill: '#475569', fontSize: 10 }}
                                            minTickGap={30}
                                        />
                                        <YAxis
                                            hide
                                            domain={['auto', 'auto']}
                                        />
                                        <Tooltip
                                            contentStyle={{ backgroundColor: '#000', border: 'none', borderRadius: '12px', fontSize: '12px' }}
                                            itemStyle={{ color: '#fff' }}
                                        />
                                        <Area
                                            type="monotone"
                                            dataKey="price"
                                            stroke="#fff"
                                            strokeWidth={2}
                                            fillOpacity={1}
                                            fill="url(#colorPrice)"
                                            animationDuration={1500}
                                        />
                                    </AreaChart>
                                </ResponsiveContainer>
                            )}
                        </CardContent>
                    </Card>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <Button onClick={() => handleAction('COMPRA')} className="h-16 rounded-2xl bg-white text-black font-bold hover:bg-slate-200">
                            <Plus size={18} className="mr-2" /> COMPRAR
                        </Button>
                        <Button onClick={() => handleAction('VENTA')} variant="outline" className="h-16 rounded-2xl border-white/10 hover:bg-white/5">
                            <Minus size={18} className="mr-2" /> VENDER
                        </Button>
                        <Button onClick={() => handleAction('DEPÓSITO')} variant="outline" className="h-16 rounded-2xl border-white/10 hover:bg-white/5">
                            <ArrowDown size={18} className="mr-2" /> DEPOSITAR
                        </Button>
                        <Button onClick={() => handleAction('RETIRO')} variant="outline" className="h-16 rounded-2xl border-white/10 hover:bg-white/5">
                            <ArrowUp size={18} className="mr-2" /> RETIRAR
                        </Button>
                    </div>
                </div>

                <div className="xl:col-span-1 space-y-6">
                    <p className="text-[10px] uppercase tracking-[0.4em] font-bold text-slate-500 pl-2">Watchlist_Terminal</p>
                    <div className="space-y-3">
                        {WATCHLIST.map((symbol) => (
                            <button
                                key={symbol}
                                onClick={() => setActiveSymbol(symbol)}
                                className={`w-full flex items-center justify-between p-5 rounded-3xl transition-all border ${activeSymbol === symbol
                                    ? "bg-white text-black border-white"
                                    : "bg-white/5 text-white border-white/5 hover:border-white/20 hover:bg-white/[0.08]"
                                    }`}
                            >
                                <span className="font-bold tracking-widest font-mono">{symbol}</span>
                                <Activity size={16} className={activeSymbol === symbol ? "opacity-100" : "opacity-20"} />
                            </button>
                        ))}
                    </div>

                    <Card className="glass border-white/5 bg-blue-500/5">
                        <CardContent className="p-6">
                            <div className="flex items-center gap-3 mb-4">
                                <Wallet size={20} className="text-blue-400" />
                                <span className="font-bold text-sm tracking-tighter">ASSETS_SUMMARY</span>
                            </div>
                            <p className="text-2xl font-mono text-white">
                                ${data?.portfolios?.[0]?.balance?.toLocaleString() || "0.00"}
                            </p>
                            <p className="text-[10px] text-slate-500 uppercase mt-1">Total Portfolios Value</p>
                        </CardContent>
                    </Card>
                </div>
            </div>

            <div className="flex items-center justify-center pt-10">
                <p className="text-[10px] text-zinc-800 uppercase tracking-[0.6em] font-mono">Finsight_Quant_Engine_v1.0.8</p>
            </div>
        </div>
    );
}